        public static bool GenHeadquarter(GenerationProgress progress, int x2, int y2) {
            if (progress != null) {
                progress.Message = "Localization";
                progress.Set(0.99f);
            }

            int width = Tiles.GetLength(1);
            int height = Tiles.GetLength(0);

            for (int y = 0; y < height; y++) {
                for (int x = 0; x < width; x++) {
                    int worldX = x2 + x;
                    int worldY = y2 - y;

                    if (!WorldGen.InWorld(worldX, worldY, 10)) { continue; }

                    Tile tile = Framing.GetTileSafely(worldX, worldY);
                    tile.ClearEverything();

                    switch (Tiles[y, x]) {
                        case 0: break;
                        case 1: tile.TileType = (ushort)TileType<SwampMud>(); tile.HasTile = true; break;
                        case 2: tile.TileType = (ushort)TileType<SwampWood>(); tile.HasTile = true; break;
                        case 3: tile.TileType = (ushort)TileType<CoughwoodTile>(); tile.HasTile = true; break;
                        case 4: tile.TileType = TileID.Mudstone; tile.HasTile = true; break;
                        case 5: tile.TileType = TileID.IronBrick; tile.HasTile = true; break;
                        case 6: tile.TileType = TileID.StoneSlab; tile.HasTile = true; break;
                        case 7: tile.TileType = (ushort)TileType<PeatBlock>(); tile.HasTile = true; break;
                        case 8: tile.TileType = TileID.Chain; tile.HasTile = true; break;
                        case 9: tile.TileType = TileID.Titanstone; tile.HasTile = true; tile.IsActuated = true; break;
                        case a: tile.TileType = TileID.Titanstone; tile.HasTile = true; break;
                        case b: tile.TileType = (ushort)TileType<BrambleSpikes>(); tile.HasTile = true; break;
                        case c: WorldGen.PlaceTile(worldX, worldY, TileType<CoughwoodPlatform>()); break; 
                    }
                    //3 - 257, 4 - 24, 5 - 147, 6 - 137
                    switch (Wales[y, x]) {
                        case 0: break;
                        case 1: tile.WallType = (ushort)WallType<SwampWall>(); break;
                        case 2: tile.WallType = WallID.Rocks2Echo; break;
                        case 3: tile.WallType = WallID.Cave2Echo; break;
                        case 4: tile.WallType = WallID.MudstoneBrick; break;
                        case 5: tile.WallType = WallID.StoneSlab; break;
                        case 6: tile.WallType = WallID.Lavafall; break;
                        case 7: tile.WallType = (ushort)WallType<SwampWoodWall>(); break;
                        case 8: tile.WallType = (ushort)WallType<CoughwoodWall>(); break;
                        case 9: tile.WallType = WallID.AshWoodFence; break;
                        case a: tile.WallType = (ushort)WallType<CoughwoodFence>(); break;
                        case b: tile.WallType = WallID.IronBrick; break;
                        case c: tile.WallType = WallID.IronFence; break;

                    }
                    switch (Slope[y, x]) {
                        case 0: break;
                        case 1: tile.IsHalfBlock = true; break;
                        case 2: tile.Slope = SlopeType.SlopeDownRight; break;
                        case 3: tile.Slope = SlopeType.SlopeUpLeft; break;
                        case 4: tile.Slope = SlopeType.SlopeUpRight; break;
                        case 5: tile.Slope = SlopeType.SlopeDownLeft; break;
                    }
                    switch (Liquid[y, x]) {
                        case 0: break;
                        case 1: tile.LiquidType = LiquidID.Lava; tile.LiquidAmount = 255; break;
                    }
                }
            }
            return true;
        }
    }
}